class Solution(object):
    def canThreePartsEqualSum(self, arr):
        total = sum(arr)
        if total % 3 != 0:
            return False
        target = total // 3
        curr_sum = 0
        count = 0
        for i in range(len(arr) - 1):
            curr_sum += arr[i]
            if curr_sum == target * (count + 1):
                count += 1
                if count == 2:
                    return True
        return False
